function escapeHtml(value) {
  return String(value ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;");
}

function slugify(value) {
  return String(value ?? "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "");
}

function shortText(value, maxLength = 180) {
  const text = String(value ?? "").replace(/\s+/g, " ").trim();
  if (text.length <= maxLength) return text;
  return `${text.slice(0, maxLength - 1).trim()}…`;
}

function firstKeywords(value, limit = 3) {
  const stopwords = new Set([
    "und", "oder", "der", "die", "das", "des", "dem", "den", "mit", "von", "fur",
    "eine", "einer", "eines", "einem", "einen", "ein", "im", "in", "am", "an", "zu",
    "auf", "als", "bei", "ist", "sind", "aus", "uber", "zum", "zur", "ii", "i"
  ]);

  const words = String(value ?? "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, " ")
    .split(/\s+/)
    .filter((word) => word.length > 2 && !stopwords.has(word));

  return Array.from(new Set(words)).slice(0, limit);
}

function acceptedAnswers(value, fallback = "klausur") {
  const base = String(value ?? "").trim();
  const keywords = firstKeywords(base, 4);
  const answers = new Set();
  if (base) answers.add(base);
  keywords.forEach((keyword) => answers.add(keyword));
  if (!answers.size) answers.add(fallback);
  return Array.from(answers);
}

function includesAny(haystack, needles = []) {
  return needles.some((needle) => haystack.includes(needle));
}

function mkTask(text, steps, result) {
  return {
    text,
    steps: steps.map((step) => (typeof step === "string" ? { text: step, eq: null } : step)),
    result
  };
}

function mkIntuition(core, analogy, bridge, exam = []) {
  return { core, analogy, bridge, exam };
}

function renderStructuredTheory(sections = [], warnings = []) {
  const sectionHtml = sections.map((section) => `
<div class="section-block">
  <h3>${escapeHtml(section.title)}</h3>
  ${section.body.map((paragraph) => `<p>${paragraph}</p>`).join("")}
</div>`).join("");

  const warningHtml = warnings.length ? `
<div class="section-block">
  <h3>Fehleranalyse</h3>
  ${warnings.map((warning) => `<div class="warn-box"><strong>${escapeHtml(warning.title)}</strong> ${warning.body}</div>`).join("")}
</div>` : "";

  return `${sectionHtml}${warningHtml}`;
}

