  const entry = entries.find((candidate) => candidate.kind === item.kind && includesAny(title, candidate.match));
  if (!entry) return null;

  return makeOverride({
    motivation: entry.motivation,
    sections: entry.sections,
    warnings: entry.warnings,
    intuition: mkIntuition(
      entry.core,
      entry.analogy,
      entry.bridge,
      [
        { if: `du "${chapter.title}" in einer Klausur oder einem Kurzfall erkennst`, then: entry.examRule },
        { if: "du zwischen zwei nahe liegenden Instituten oder Zugriffen schwankst", then: entry.distinctionHint }
      ]
    ),
    mastery: entry.mastery,
    tasks: buildTasks(entry)
  });

  return null;
