function wrapSvgLabel(label) {
  const words = String(label ?? "").split(/\s+/).filter(Boolean);
  const lines = [];
  let current = "";

  words.forEach((word) => {
    const candidate = current ? `${current} ${word}` : word;
    if (candidate.length <= 18 || !current) {
      current = candidate;
      return;
    }
    lines.push(current);
    current = word;
  });

  if (current) lines.push(current);
  return lines.slice(0, 3);
}

function svgTextLines(label, x, y) {
  const lines = wrapSvgLabel(label);
  return `<text x="${x}" y="${y}" fill="var(--text)" text-anchor="middle" font-family="var(--font-mono)" font-size="12">${lines.map((line, index) => `<tspan x="${x}" dy="${index === 0 ? 0 : 14}">${escapeHtml(line)}</tspan>`).join("")}</text>`;
}

function resolveGraphKind(module, chapter, item) {
  if (module.type === "text_doctrinal") return null;
  if (item.kind === "practice") return null;
  if (item.kind === "code") return module.rLab ? "code_workflow" : null;

  const title = `${chapter.title} ${item.title}`.toLowerCase();

  if (module.slug === "makro1") {
    if (includesAny(title, ["gesamtrechnung", "reales bip", "inflation und arbeitslosigkeit"])) return "makro_data";
    if (includesAny(title, ["guetermarkt", "multiplikator", "sparparadox"])) return "makro_goods";
    if (includesAny(title, ["finanzmaerkte i", "geldnachfrage", "zentralbanksteuerung"])) return "makro_money";
    if (includesAny(title, ["is-lm-grundmodell"])) return "makro_islm";
    if (includesAny(title, ["realzins", "risikopraemie", "risikoprämie", "erweitertes is-lm"])) return "makro_risk";
    if (includesAny(title, ["arbeitsmarkt", "lohnsetzung", "preissetzung", "produktionspotenzial"])) return "makro_labor";
    if (includesAny(title, ["phillipskurve", "nairu", "inflationsdynamik"])) return "makro_phillips";
    return null;
  }

  if (module.slug === "r") {
    if (includesAny(title, ["funktionen, sequenzen und 2d-plots"])) return "math_functions";
    if (includesAny(title, ["matrixprodukte in r", "determinanten, inverse und lineare systeme"])) return "math_matrix";
    if (includesAny(title, ["ableitungen, newton und nullstellensuche"])) return "math_derivative";
    if (includesAny(title, ["multivariate funktionen, persp() und hesse-matrix"])) return "math_multivar";
    if (includesAny(title, ["integrale und numerische mehrdimensionalitaet"])) return "math_integral";
    if (includesAny(title, ["univariate optimierung mit optimise() und nlm()"])) return "math_univar_opt";
    if (includesAny(title, ["multivariate optimierung und restriktionen"])) return "math_lagrange";
    return null;
  }

  if (module.slug === "mathematik") {
    if (includesAny(title, ["funktionen und gleichungen"])) return "math_functions";
    if (includesAny(title, ["matrizen und matrix-algebra", "masszahlen", "inversen", "eigenwerte"])) return "math_matrix";
    if (includesAny(title, ["univariate differenzialrechnung"])) return "math_derivative";
    if (includesAny(title, ["univariate optimierung"])) return "math_univar_opt";
    if (includesAny(title, ["funktionen mehrerer variablen"])) return "math_multivar";
    if (includesAny(title, ["multivariate optimierung", "lagrange"])) return "math_lagrange";
    if (includesAny(title, ["integralrechnung"])) return "math_integral";
    return null;
  }

  if (module.slug === "finanzwirtschaft") {
    if (includesAny(title, ["liquiditaetsplanung", "goldene bilanzregel", "kapitalbedarfsplanung"])) return "fin_liquidity";
    if (includesAny(title, ["intertemporale wahl", "zeitpraeferenzen", "budgetgerade"])) return "fin_budget";
    if (includesAny(title, ["kapitalwert", "fisher-separation", "interner zinsfuss", "internen zinsfusses", "kapitalwertfunktion"])) return "fin_npv";
    if (includesAny(title, ["unsicherheit", "verlustwahrscheinlichkeit", "risikozuschlag", "sicherheitsaquivalent", "sicherheitsaequivalent"])) return "fin_uncertainty";
    if (includesAny(title, ["kapitalstruktur", "gesamtkapitalkosten", "leverage"])) return "fin_leverage";
    return null;
  }

  if (module.slug === "internationale-wirtschaftsbeziehungen") {
    if (includesAny(title, ["ricardo", "opportunitaetskosten", "komparative vorteile"])) return "iwb_ricardo";
    if (includesAny(title, ["handelspolitik i", "handelspolitik ii", "importzoelle", "sanktionen", "importquoten"])) return "iwb_tariff";
    if (includesAny(title, ["ungedeckte zinsparitaet", "kaufkraftparitaet"])) return "iwb_uip";
    if (includesAny(title, ["quantitaetstheorie", "geldmengenwachstum", "fisher-effekt", "reale zinsparitaet"])) return "iwb_money";
    if (includesAny(title, ["kurzfristige wechselkurse", "overshooting"])) return "iwb_overshooting";
    if (includesAny(title, ["trilemma", "balassa-samuelson"])) return "iwb_trilemma";
    return null;
  }

  if (module.slug === "statistik") {
    if (includesAny(title, ["haeufigkeitsverteilungen", "histogramme", "balkendiagramme", "streumasse", "boxplots", "stetige zufallsvariablen", "normalverteilung"])) return "stat_distribution";
    if (includesAny(title, ["bivariate tabellen", "korrelation", "fehlschluesse", "bedingte verteilungen"])) return "stat_correlation";
    if (includesAny(title, ["diskrete zufallsvariablen", "binomial", "poisson"])) return "stat_binomial";
    if (includesAny(title, ["schaetzverfahren", "konfidenzintervalle", "konfidenzintervall"])) return "stat_ci";
    if (includesAny(title, ["hypothesentests", "zwei-stichproben", "varianzanalyse"])) return "stat_test";
    if (includesAny(title, ["modellierung", "regression"])) return "stat_regression";
    return null;
  }

  if (module.slug === "oekonometrie") {
    if (includesAny(title, ["lineare modell", "ols-schaetzung", "prognose", "bestimmtheitsmass"])) return "econ_ols";
    if (includesAny(title, ["annahmen"])) return "econ_assumptions";
    if (includesAny(title, ["gauss-markov", "eigenschaften", "fehlervarianz", "asymptot"])) return "econ_sampling";
    if (includesAny(title, ["intervallschaetzung", "normales lineares modell", "hypothesentest", "tests"])) return "econ_test";
    if (includesAny(title, ["multikollinear"])) return "econ_collinearity";
    if (includesAny(title, ["heteroskedast"])) return "econ_hetero";
    if (includesAny(title, ["autokorrelation"])) return "econ_autocorr";
    return null;
  }

  return null;
}

function shouldRenderGraph(module, chapter, item) {
  return Boolean(resolveGraphKind(module, chapter, item));
}

function buildWorkflowPanel(module, chapter, allItems, index) {
  const previous = allItems[index - 1];
  const next = allItems[index + 1];
  const currentItem = allItems[index];
  const isCodeWorkflow = currentItem?.kind === "code" || module.type === "quantitative_coding";

  let title = "Lernvisualisierung";
  let intro = `Die Grafik verdichtet "${chapter.title}" zu einer klaren Lernlogik. Nutze sie, um Reihenfolge, Mechanismus und typische Klausurbewegung im Kopf zu behalten.`;
  let caption = `Arbeite dich von links nach rechts durch die Logik von "${chapter.title}".`;
  let nodes = [];

  if (isCodeWorkflow) {
    title = "Analyse-Workflow";
    intro = `Lies "${chapter.title}" als Daten- und Analyseworkflow: Frage klar machen, Modell oder Test waehlen, Output lesen, oekonomisch interpretieren.`;
    caption = "Erst die fachliche Frage, dann der Code- oder Modellschritt, danach die Deutung des Outputs.";
    nodes = [
      { x: 110, y: 96, label: "Frage" },
      { x: 280, y: 96, label: "Daten" },
      { x: 450, y: 96, label: chapter.title },
      { x: 620, y: 96, label: "Output" },
      { x: 365, y: 238, label: next?.title || "Interpretation" }
    ];
  } else if (module.type === "quantitative") {
    title = "Mechanismusgrafik";
    intro = `Diese Grafik zeigt "${chapter.title}" als Mechanismus: Ausgangspunkt, zentrale Beziehung, Wirkungsrichtung und oekonomische Schlussfolgerung.`;
    caption = `Merke dir bei "${chapter.title}" besonders Ursache, Richtung und Interpretation.`;
    nodes = [
      { x: 110, y: 96, label: previous?.title || "Ausgangspunkt" },
      { x: 280, y: 96, label: chapter.title },
      { x: 450, y: 96, label: "Mechanismus" },
      { x: 620, y: 96, label: "Ergebnis" },
      { x: 365, y: 238, label: next?.title || "Transfer" }
    ];
  } else {
    title = "Entscheidungslogik";
    intro = `Statt einer mathematischen Grafik brauchst du hier vor allem eine klare Denkstruktur: Ausgangsfrage, Kriterien, Abwaegung und Schluss.`;
    caption = `Nutze die Grafik als Raster fuer Vergleichs- und Transferfragen zu "${chapter.title}".`;
    nodes = [
      { x: 110, y: 96, label: "Ausgangsfrage" },
      { x: 280, y: 96, label: chapter.title },
      { x: 450, y: 96, label: "Kriterien" },
      { x: 620, y: 96, label: "Schluss" },
      { x: 365, y: 238, label: next?.title || previous?.title || "Transfer" }
    ];
  }

  return `<div class="panel active generated-graph-panel">
<div class="section-block">
  <h3>${escapeHtml(title)}</h3>
  <p>${escapeHtml(intro)}</p>
</div>
<div class="generated-flow-shell">
  <svg class="generated-flow-svg" viewBox="0 0 760 340" role="img" aria-label="Visualisierung fuer ${escapeHtml(chapter.title)}">
    <defs>
      <linearGradient id="flowGlow_${escapeHtml(chapter.id)}" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stop-color="var(--accent)" stop-opacity="0.18"></stop>
        <stop offset="100%" stop-color="var(--accent2)" stop-opacity="0.08"></stop>
      </linearGradient>
    </defs>
    <rect x="18" y="18" width="724" height="304" rx="24" fill="url(#flowGlow_${escapeHtml(chapter.id)})"></rect>
    <g stroke="var(--accent)" stroke-opacity="0.48" stroke-width="2" fill="none">
      <path d="M170 96 L220 96"></path>
      <path d="M340 96 L390 96"></path>
      <path d="M510 96 L560 96"></path>
      <path d="M450 122 L390 206"></path>
      <path d="M280 122 L340 206"></path>
    </g>
    ${nodes.map((node) => `<g transform="translate(${node.x}, ${node.y})">
      <rect x="-82" y="-30" width="164" height="60" rx="18" fill="var(--surface2)" stroke="var(--accent)" stroke-opacity="0.28"></rect>
      ${svgTextLines(node.label, 0, -4)}
    </g>`).join("")}
  </svg>
  <p class="generated-flow-caption">${escapeHtml(caption)}</p>
</div>
</div>`;
}

